   *         {@link LowerCaseFilter}, {@link StopFilter},
   *         {@link KeywordMarkerTokenFilter} if a stem exclusion set is provided, and
   *         {@link SnowballFilter}
   */
  @Override
  protected TokenStreamComponents createComponents(String fieldName,
